INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Modernisation de la gestion des ressources humaines', 'Formation sur les nouvelles pratiques et outils pour moderniser la gestion RH.', 3, 200000.00, 'entreprise', '2026-04-15', 30, '2026-02-13 12:33:47', '2026-02-13 12:33:47', NULL, E'--- OBJECTIFS ---\n• Comprendre les nouvelles tendances RH\n• Utiliser des outils digitaux pour la gestion du personnel\n• Optimiser la performance et la motivation des équipes\n• Assurer la conformité légale et réglementaire\n\n--- OBJECTIFS DÉTAILLÉS ---\nInitier les participants aux pratiques modernes de gestion RH et leur apprendre à utiliser des outils digitaux pour optimiser la performance.\n\n--- PRÉREQUIS ---\nConnaissances de base en gestion ou RH souhaitées.\n\n--- CONTENU ---\nModule 1 : Introduction aux nouvelles pratiques RH\nModule 2 : Digitalisation de la gestion du personnel\nModule 3 : Outils modernes de suivi et reporting\nModule 4 : Atelier pratique – Mise en œuvre d’un plan RH moderne\n\n--- NIVEAU ---\nIntermédiaire\n\n--- PUBLIC ---\nResponsables RH, managers, chefs d’entreprise et étudiants en gestion.\n\n--- MÉTHODES ---\nCours interactifs, démonstrations, ateliers pratiques et études de cas.\n\n--- SUPPORTS ---\nLogiciels RH, tableurs Excel, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
